     1→import * as fs from 'node:fs';
     2→import { it, assert } from 'vitest';
     3→import { compile, compileModule } from 'svelte/compiler';
     4→import { try_load_json } from '../helpers.js';
     5→import { suite, type BaseTest } from '../suite.js';
     6→import type { CompileError } from '#compiler';
     7→
     8→interface ValidatorTest extends BaseTest {
     9→	compileOptions?: Partial<import('#compiler').CompileOptions>;
    10→	error?: {
    11→		code: string;
    12→		message: string;
    13→	};
    14→}
    15→
    16→/**
    17→ * Remove the "https://svelte.dev/e/..." link
    18→ */
    19→function strip_link(message: string) {
    20→	return message.slice(0, message.lastIndexOf('\n'));
    21→}
    22→
    23→const { test, run } = suite<ValidatorTest>(async (config, cwd) => {
    24→	const expected_warnings = try_load_json(`${cwd}/warnings.json`) || [];
    25→	const expected_errors = try_load_json(`${cwd}/errors.json`);
    26→	const options = try_load_json(`${cwd}/options.json`);
    27→
    28→	let error;
    29→
    30→	try {
    31→		const module = fs.existsSync(`${cwd}/input.svelte.js`);
    32→
    33→		const input = (
    34→			module
    35→				? fs.readFileSync(`${cwd}/input.svelte.js`, 'utf-8')
    36→				: fs.readFileSync(`${cwd}/input.svelte`, 'utf-8')
    37→		)
    38→			.replace(/\s+$/, '')
    39→			.replace(/\r/g, '');
    40→
