    42→			...config.compileOptions,
    43→			generate: false,
    44→			...options
    45→		});
    46→
    47→		assert.deepEqual(
    48→			warnings.map((w) => ({
    49→				code: w.code,
    50→				message: strip_link(w.message),
    51→				start: { line: w.start?.line, column: w.start?.column },
    52→				end: { line: w.end?.line, column: w.end?.column }
    53→			})),
    54→			expected_warnings
    55→		);
    56→	} catch (e) {
    57→		error = e as CompileError;
    58→	}
    59→
    60→	const expected = expected_errors && expected_errors[0];
    61→
    62→	if (error && expected) {
    63→		assert.deepEqual(
    64→			{
    65→				code: error.code,
    66→				message: strip_link(error.message),
    67→				start: { line: error.start?.line, column: error.start?.column },
    68→				end: { line: error.end?.line, column: error.end?.column }
    69→			},
    70→			{
    71→				code: expected.code,
    72→				message: expected.message,
    73→				start: expected.start,
    74→				end: expected.end
    75→			}
    76→		);
    77→	} else if (expected) {
    78→		throw new Error(`Expected an error: ${expected.message}`);
    79→	} else if (error) {
